using UnityEngine;
using Climbing;

public class FindAnyPlayer
{
    public static string Inspect()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "No ClimbController found in scene.";

        GameObject pm = cc.gameObject;
        Rigidbody rb = pm.GetComponent<Rigidbody>();
        ThirdPersonController tpc = pm.GetComponent<ThirdPersonController>();

        string report = $"--- Player Found: {pm.name} ---\n";
        report += $"Position: {pm.transform.position}\n";
        if (rb != null) report += $"RB: Gravity={rb.useGravity}, Kinematic={rb.isKinematic}\n";
        if (tpc != null) report += $"TPC: Grounded={tpc.isGrounded}, onAir={tpc.onAir}\n";

        RaycastHit hit;
        if (Physics.Raycast(pm.transform.position + Vector3.up * 0.1f, Vector3.down, out hit, 100f)) {
            report += $"Below: {hit.collider.name} at {hit.distance} units.\n";
        } else {
            report += "Below: NOTHING for 100 units.\n";
        }

        return report;
    }
}
